```java
import jakarta.validation.constraints.*;
import org.springframework.boot.context.properties.ConfigurationProperties;
import org.springframework.validation.annotation.Validated;

@ConfigurationProperties(prefix = "payment.gateway")
@Validated
public record PaymentGatewayProps(
    @NotBlank String url,
    @Min(100) @Max(30000) int timeoutMs,
    @Min(1) @Max(5) int maxRetries,
    @NotBlank String apiKey
) {}
```

```java
@SpringBootApplication
@ConfigurationPropertiesScan  // finds all @ConfigurationProperties in package
public class Application {
    public static void main(String[] args) { SpringApplication.run(Application.class, args); }
}
```

```java
interface EmailService { void send(String to, String body); }

@Service @Profile({"dev", "test"})
class MockEmailService implements EmailService {
    @Override public void send(String to, String body) {
        System.out.println("[MOCK] Email to " + to + ": " + body);
    }
}

@Service @Profile("prod")
class SmtpEmailService implements EmailService {
    private final PaymentGatewayProps props;
    SmtpEmailService(PaymentGatewayProps p) { props = p; }
    @Override public void send(String to, String body) { /* real SMTP */ }
}
```

```java
@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.NONE)
@ActiveProfiles("dev")
class PaymentGatewayPropsTest {
    @Autowired PaymentGatewayProps props;
    @Autowired EmailService emailService;

    @Test void props_loadedFromDevProfile() {
        assertEquals("https://sandbox.razorpay.com", props.url());
        assertEquals(3, props.maxRetries());
    }

    @Test void emailService_isDevMock() {
        assertInstanceOf(MockEmailService.class, emailService);
    }
}
```

